"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[61611],{35610(e,t,a){a.r(t),a.d(t,{assets:()=>d,contentTitle:()=>s,default:()=>l,frontMatter:()=>r,metadata:()=>i,toc:()=>c});let i=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 and IAS 39/application-of-the-highly-probable-r-020c7d4fb3","title":"Application of the Highly Probable Requirement when a Specific Derivative is Designated as a Hedging Instrument (IFRS 9 and IAS 39)","description":"March 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 and IAS 39/Application of the Highly Probable Requirement when a Specific Derivative is Designated as a Hedging Instrument.md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 and IAS 39","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-and-ias-39-11011ae3c4/application-of-the-highly-probable-r-020c7d4fb3","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-and-ias-39-11011ae3c4/application-of-the-highly-probable-r-020c7d4fb3","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"application-of-the-highly-probable-r-020c7d4fb3","title":"Application of the Highly Probable Requirement when a Specific Derivative is Designated as a Hedging Instrument (IFRS 9 and IAS 39)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-and-ias-39-11011ae3c4/application-of-the-highly-probable-r-020c7d4fb3","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"TLTRO III Transactions (IFRS 9 and IAS 20)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-and-ias-20-74020d5e15/tltro-iii-transactions-ifrs-9-and-ia-e175efc16b"},"next":{"title":"\u514D\u8CAC\u8072\u660E","permalink":"/docs/6-ey-bbb2f2ea9c/igaap-2023-60f8ed3559/0-e2d6c7cbbc/doc-db8a0c716f"}}');var n=a(74848),o=a(28453);let r={id:"application-of-the-highly-probable-r-020c7d4fb3",title:"Application of the Highly Probable Requirement when a Specific Derivative is Designated as a Hedging Instrument (IFRS 9 and IAS 39)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-and-ias-39-11011ae3c4/application-of-the-highly-probable-r-020c7d4fb3",sidebar_position:1},s="Application of the Highly Probable Requirement when a Specific Derivative is Designated as a Hedging Instrument (IFRS 9 and IAS 39)",d={},c=[];function h(e){let t={h1:"h1",header:"header",p:"p",...(0,o.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"application-of-the-highly-probable-requirement-when-a-specific-derivative-is-designated-as-a-hedging-instrument-ifrs-9-and-ias-39",children:"Application of the Highly Probable Requirement when a Specific Derivative is Designated as a Hedging Instrument (IFRS 9 and IAS 39)"})}),"\n",(0,n.jsx)(t.p,{children:"March 2019"}),"\n",(0,n.jsx)(t.p,{children:"The Committee received a request about the requirement in IFRS 9 and IAS 39 that a forecast transaction must be \u2018highly probable\u2019 to qualify as a hedged item in a cash flow hedge relationship. The request asked how an entity applies that requirement when the notional amount of the derivative designated as a hedging instrument (load following swap) varies depending on the outcome of the hedged item (forecast energy sales)."}),"\n",(0,n.jsx)(t.p,{children:"The responses to outreach performed on the request and those received in comment letters confirmed that the financial instrument described in the request is not common. The comment letters also confirmed the views expressed by some Committee members that the request relates to the broader matter of how uncertainty over the timing and magnitude of a forecast transaction affects the highly probable assessment applying IFRS 9 and IAS 39."}),"\n",(0,n.jsx)(t.p,{children:"The Committee observed that, in a cash flow hedge, a forecast transaction can be a hedged item if, and only if, it is highly probable (paragraphs 6.3.1 and 6.3.3 of IFRS 9 and paragraphs 86(b) and 88(c) of IAS 39). When assessing whether a forecast transaction (in the request, the forecast energy sales) is highly probable, an entity considers uncertainty over both the timing and magnitude of the forecast transaction (paragraphs F.3.7 and F.3.11 of the Implementation Guidance accompanying IAS 39)."}),"\n",(0,n.jsx)(t.p,{children:"The Committee also observed that, for hedge accounting purposes, the entity must document the forecast energy sales with sufficient specificity in terms of timing and magnitude so that when such transactions occur the entity can identify whether the transaction is the hedged transaction. Consequently, the forecast energy sales cannot be specified solely as a percentage of sales during a period because that would lack the required specificity (paragraphs F.3.10 and F.3.11 of the Implementation Guidance accompanying IAS 39)."}),"\n",(0,n.jsx)(t.p,{children:"In addition, the Committee observed that the terms of the hedging instrument (in the request, the load following swap) do not affect the highly probable assessment because the highly probable requirement is applicable to the hedged item."}),"\n",(0,n.jsx)(t.p,{children:"The Committee noted that the highly probable requirement in IFRS 9 is not new; IAS 39 includes the same requirement. The Board decided not to carry forward any of the hedge accounting related Implementation Guidance that accompanied IAS 39; nonetheless paragraph BC6.95 of IFRS 9 explains that not carrying forward the Implementation Guidance did not mean that the Board had rejected that guidance."}),"\n",(0,n.jsx)(t.p,{children:"The Committee concluded that the requirements in IFRS 9 and IAS 39 provide an adequate basis for an entity to determine whether a forecast transaction is highly probable. Consequently, the Committee decided not to add this matter to its standard-setting agenda."})]})}function l(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(h,{...e})}):h(e)}},28453(e,t,a){a.d(t,{R:()=>r,x:()=>s});var i=a(96540);let n={},o=i.createContext(n);function r(e){let t=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:r(e.components),i.createElement(o.Provider,{value:t},e.children)}}}]);